function getWikiFallback(brand, model) {
  const key = `${brand} ${model}`.toLowerCase();
  // exact match
  if (WIKI_IMAGES[key]) return WIKI_IMAGES[key];
  // partial match
  const entry = Object.entries(WIKI_IMAGES).find(([k]) => key.includes(k) || k.includes(key.split(" ").slice(0, 2).join(" ")));
  return entry ? entry[1] : null;
}

/* ─── Vehicle Image con shimmer + fallback automático ────── */
function VehicleImage({ vehicle, className, style, height = 170 }) {
  const [src, setSrc] = useState(vehicle.imageUrl || null);
  const [stage, setStage] = useState(vehicle.imageUrl ? "loading" : "wiki-pending");
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    const wikiSrc = getWikiFallback(vehicle.brand, vehicle.model);
    setSrc(vehicle.imageUrl || wikiSrc || null);
    setStage(vehicle.imageUrl ? "loading" : wikiSrc ? "loading" : "placeholder");
    setLoaded(false);
  }, [vehicle.imageUrl, vehicle.brand, vehicle.model]);

  const handleLoad = () => setLoaded(true);

  const handleError = () => {
    if (stage === "loading" && src !== null) {
      const wiki = getWikiFallback(vehicle.brand, vehicle.model);
      if (wiki && wiki !== src) { setSrc(wiki); setLoaded(false); return; }
    }
    setSrc(null);
    setStage("placeholder");
  };

  const CarSvg = () => (
    <svg viewBox="0 0 64 32" fill="none" style={{width:52,height:26}}>
      <rect x="4" y="14" width="56" height="14" rx="4" fill="currentColor" opacity=".2"/>
      <path d="M10 14L18 6h28l8 8" stroke="currentColor" strokeWidth="2" fill="none" opacity=".35"/>
      <circle cx="16" cy="28" r="5" fill="currentColor" opacity=".3"/>
      <circle cx="48" cy="28" r="5" fill="currentColor" opacity=".3"/>
    </svg>
  );

  // Show placeholder if no src
  if (!src || stage === "placeholder") {
    return (
      <div className="img-loading-wrap" style={{height}}>
        <div className="img-loading-icon" style={{color:"rgba(255,255,255,.18)"}}>
          <CarSvg />
          <span style={{fontSize:".6rem",fontFamily:"var(--font-hd)",letterSpacing:".12em",textTransform:"uppercase"}}>{vehicle.brand}</span>
        </div>
      </div>
    );
  }

  return (
    <div className="img-loading-wrap" style={{height}}>
      {/* Shimmer shown while image loads */}
      {!loaded && (
        <>
          <div className="img-loading-shimmer" />
          <div className="img-loading-icon">
            <CarSvg />
            <span style={{fontSize:".6rem",fontFamily:"var(--font-hd)",letterSpacing:".12em",textTransform:"uppercase",color:"rgba(255,255,255,.25)"}}>{vehicle.brand} {vehicle.model}</span>
            <span style={{fontSize:".55rem",color:"rgba(255,255,255,.15)"}}>Cargando imagen…</span>
          </div>
        </>
      )}
      <img
        className={loaded ? `img-fade-in${className ? " " + className : ""}` : ""}
        src={src}
        alt={`${vehicle.brand} ${vehicle.model}`}
        style={{
          ...style,
          position: loaded ? "relative" : "absolute",
          width: "100%", height: "100%",
          objectFit: "cover",
          opacity: loaded ? 1 : 0,
          transition: "opacity .3s ease",
        }}
        onLoad={handleLoad}
        onError={handleError}
        loading="lazy"
      />
    </div>
  );
}

